svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var pie = svgEl.querySelector('#pie');
    var R   = 195, PUSH = 14;
    var FRAME_W = 920, FRAME_H = 390;
    var CX = 220, CY = 195;

    function easeOutCubic(t) { return 1 - Math.pow(1-t, 3); }
    function easeOutBack(t)  { var c1=1.70158,c3=c1+1; return 1+c3*Math.pow(t-1,3)+c1*Math.pow(t-1,2); }

    var sliceEls = ctx.$$all('.slice-g');
    var SPIN_DUR = 550, STAGGER = 225, FADE_DUR = 800;
    var startTime = null;

    sliceEls.forEach(function (g) { g.style.opacity = '0'; });
    var holeEl = svgEl.querySelector('#hole-group');
    holeEl.style.opacity = '0';

    function animateSlices(ts) {
      if (!startTime) startTime = ts;
      var elapsed = ts - startTime;
      sliceEls.forEach(function (g, i) {
        var t     = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / SPIN_DUR));
        var tFade = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / FADE_DUR));
        var span  = parseFloat(g.getAttribute('data-span'));
        g.setAttribute('transform', 'rotate('+(easeOutBack(t)*span-span).toFixed(3)+')');
        g.style.opacity = easeOutCubic(tFade).toFixed(3);
      });
      var holeStart = (sliceEls.length-1)*STAGGER + SPIN_DUR*0.7;
      holeEl.style.opacity = easeOutCubic(Math.max(0, Math.min(1, (elapsed-holeStart)/300))).toFixed(3);
      var totalDur = (sliceEls.length-1)*STAGGER + SPIN_DUR + 300;
      if (elapsed < totalDur) {
        requestAnimationFrame(animateSlices);
      } else {
        sliceEls.forEach(function (g) { g.removeAttribute('transform'); g.style.opacity = ''; });
        holeEl.style.opacity = '1';
        pie.classList.add('ready');
      }
    }
    requestAnimationFrame(animateSlices);

    var tip    = svgEl.querySelector('#tip');
    var tipBg  = svgEl.querySelector('#tip-bg');
    var tipBdr = svgEl.querySelector('#tip-bdr');
    var tipArr = svgEl.querySelector('#tip-arr');
    var tipVal = svgEl.querySelector('#tip-val');
    var tipLbl = svgEl.querySelector('#tip-lbl');
    var tipPct = svgEl.querySelector('#tip-pct');

    function showTip(g) {
      var midDeg = parseFloat(g.getAttribute('data-mid'));
      var label  = g.getAttribute('data-label');
      var val    = g.getAttribute('data-val');
      var pct    = g.getAttribute('data-pct');
      var midRad = midDeg * Math.PI / 180;
      var dx = Math.cos(midRad), dy = Math.sin(midRad);
      var tipX = CX + dx * R, tipY = CY + dy * R;

      tipVal.textContent = val; tipLbl.textContent = label; tipPct.textContent = pct;
      var pad = 20;
      var hw = Math.max(tipVal.getBBox().width+pad, tipLbl.getBBox().width+pad, tipPct.getBBox().width+pad, 60) / 2;
      var bh = 56, rx9 = 9, tw = 10, TAIL = 8;

      var bCx = tipX;
      if (bCx - hw < 8)    bCx = 8 + hw;
      if (bCx + hw > FRAME_W - 8) bCx = FRAME_W - 8 - hw;
      var flip = dy > 0;
      var bT, bB;
      var tailTipY;
      if (!flip) { bT = tipY - TAIL - bh; bB = tipY - TAIL; }
      else       { bT = tipY + TAIL;      bB = tipY + TAIL + bh; }
      if (bT < 8)   { bT = 8;   bB = bT + bh; }
      if (bB > FRAME_H - 8) { bB = FRAME_H - 8; bT = bB - bh; }
      if (tipY <= bT) {
        flip = true;
      } else if (tipY >= bB) {
        flip = false;
      } else if (!flip) {
        bT = Math.min(FRAME_H - 8 - bh, tipY + TAIL);
        bB = bT + bh;
        flip = true;
      } else {
        bB = Math.max(8 + bh, tipY - TAIL);
        bT = bB - bh;
        flip = false;
      }
      tailTipY = flip ? Math.min(tipY, bT - 4) : Math.max(tipY, bB + 4);
      var bL = bCx - hw, bR = bCx + hw;

      tipBg.setAttribute('x', bL); tipBg.setAttribute('y', bT);
      tipBg.setAttribute('width', hw*2); tipBg.setAttribute('height', bh);

      var openPath, tailPath;
      if (flip) {
        openPath = 'M'+(bCx-tw)+','+bT+' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+' L'+(bCx+tw)+','+bT;
        tailPath = 'M'+(bCx+tw)+','+bT+' L'+bCx+','+tailTipY+' L'+(bCx-tw)+','+bT;
      } else {
        openPath = 'M'+(bCx+tw)+','+bB+' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+' L'+(bCx-tw)+','+bB;
        tailPath = 'M'+(bCx-tw)+','+bB+' L'+bCx+','+tailTipY+' L'+(bCx+tw)+','+bB;
      }
      tipBdr.setAttribute('d', openPath); tipArr.setAttribute('d', tailPath);
      tipVal.setAttribute('x', bCx); tipVal.setAttribute('y', bT + bh*0.28);
      tipLbl.setAttribute('x', bCx); tipLbl.setAttribute('y', bT + bh*0.54);
      tipPct.setAttribute('x', bCx); tipPct.setAttribute('y', bT + bh*0.78);
      tip.style.opacity = '1';
    }

    function hideTip() { tip.style.opacity = ''; }

    sliceEls.forEach(function (g) {
      var midDeg = parseFloat(g.getAttribute('data-mid'));
      var midRad = midDeg * Math.PI / 180;
      var dx = Math.cos(midRad), dy = Math.sin(midRad);
      var pathEl = svgEl.querySelector('#sp' + g.id.replace('sl', ''));

      g.addEventListener('mouseenter', function () {
        pie.classList.add('hovering');
        sliceEls.forEach(function (s) { s.classList.remove('active'); });
        g.classList.add('active');
        if (pathEl) pathEl.setAttribute('transform', 'translate('+(dx*PUSH).toFixed(1)+','+(dy*PUSH).toFixed(1)+')');
        showTip(g);
      });
      g.addEventListener('mouseleave', function () {
        g.classList.remove('active');
        if (pathEl) pathEl.removeAttribute('transform');
        hideTip();
      });
    });

    pie.addEventListener('mouseleave', function () { pie.classList.remove('hovering'); });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
